#!/usr/bin/env python3
"""
Optional Colab/local runtime wrapper for Zodiac attack experiments.

Supports:
- GPU solver path (`zodiac_gpu_solver.py`)
- Rust solver path (`open-source/gnosis/zodiac-attack`)
"""

from __future__ import annotations

import argparse
import os
import subprocess
import sys
from pathlib import Path


SCRIPT_DIR = Path(__file__).resolve().parent
HOST_ROOT = SCRIPT_DIR.parent
REPO_ROOT = HOST_ROOT.parents[2]
RUST_CRATE = REPO_ROOT / "open-source/gnosis/zodiac-attack"
RUST_MANIFEST = RUST_CRATE / "Cargo.toml"
RUST_BIN = REPO_ROOT / "target/release/zodiac-attack"


def parse_args() -> argparse.Namespace:
    p = argparse.ArgumentParser(description="Run Zodiac attack in optional Colab runtime.")
    p.add_argument("--runtime", choices=["auto", "local", "colab"], default="auto")
    p.add_argument("--engine", choices=["auto", "gpu", "rust"], default="auto")
    p.add_argument("--output", type=Path, default=Path("/tmp/zodiac-colab-best.json"))
    p.add_argument("--rounds", type=int, default=1, help="GPU rounds (or max-rounds for rust).")
    p.add_argument("--iterations", type=int, default=10000, help="Iterations per GPU round.")
    p.add_argument("--swarm-size", type=int, default=16384, help="GPU swarm size override.")
    p.add_argument("--rust-population", type=int, default=64)
    p.add_argument("--rust-generations", type=int, default=60)
    p.add_argument("--rust-sa-swaps", type=int, default=20000)
    p.add_argument("--rust-seed", type=int, default=0xC0DE0408)
    p.add_argument("--mount-drive", action="store_true", help="Attempt Google Drive mount when in Colab.")
    p.add_argument("--drive-output", type=str, default="MyDrive/zodiac/zodiac-best.json")
    return p.parse_args()


def detect_colab() -> bool:
    return "COLAB_GPU" in os.environ or "COLAB_RELEASE_TAG" in os.environ


def maybe_mount_drive(should_mount: bool) -> None:
    if not should_mount:
        return
    try:
        from google.colab import drive  # type: ignore
    except Exception:
        print("[zodiac-colab-run] google.colab not available; skipping drive mount", file=sys.stderr)
        return
    drive.mount("/content/drive")


def run_gpu_solver(args: argparse.Namespace) -> int:
    sys.path.insert(0, str(SCRIPT_DIR))
    from zodiac_gpu_solver import ZodiacGPUSolver, Z408_CIPHERTEXT

    solver = ZodiacGPUSolver(
        Z408_CIPHERTEXT,
        swarm_size=args.swarm_size,
        out_path=str(args.output),
        device="cuda",
    )
    for i in range(args.rounds):
        print(f"[zodiac-colab-run] GPU round {i + 1}/{args.rounds}", file=sys.stderr)
        solver.solve(iterations=args.iterations, temp_start=0.5, temp_end=0.01)
    return 0


def ensure_rust_binary() -> None:
    if RUST_BIN.is_file():
        return
    subprocess.run(
        [
            "cargo",
            "build",
            "--manifest-path",
            str(RUST_MANIFEST),
            "--release",
            "--bin",
            "zodiac-attack",
        ],
        check=True,
        cwd=str(REPO_ROOT),
    )


def run_rust_solver(args: argparse.Namespace) -> int:
    ensure_rust_binary()
    cmd = [
        str(RUST_BIN),
        "--strategy",
        "memetic",
        "--population",
        str(args.rust_population),
        "--generations",
        str(args.rust_generations),
        "--sa-swaps",
        str(args.rust_sa_swaps),
        "--seed",
        str(args.rust_seed),
        "--output",
        str(args.output),
        "--max-rounds",
        str(args.rounds),
    ]
    proc = subprocess.run(cmd, cwd=str(REPO_ROOT))
    return proc.returncode


def main() -> int:
    args = parse_args()
    in_colab = detect_colab()
    runtime = "colab" if (args.runtime == "auto" and in_colab) else ("local" if args.runtime == "auto" else args.runtime)
    if runtime == "colab":
        maybe_mount_drive(args.mount_drive)
        if args.mount_drive:
            args.output = Path("/content/drive") / args.drive_output

    engine = args.engine
    if engine == "auto":
        if runtime == "colab":
            engine = "gpu"
        else:
            engine = "rust"

    args.output.parent.mkdir(parents=True, exist_ok=True)
    print(f"[zodiac-colab-run] runtime={runtime} engine={engine} output={args.output}", file=sys.stderr)
    if engine == "gpu":
        return run_gpu_solver(args)
    return run_rust_solver(args)


if __name__ == "__main__":
    raise SystemExit(main())
